class Solution {
    public int strangePrinter(String s) {
        int n = s.length();
        if (n == 0) return 0;
        int[][] dp = new int[n][n];
        for (int i = 0; i < n; i++) dp[i][i] = 1;
        for (int len = 2; len <= n; len++) {
            for (int l = 0; l <= n - len; l++) {
                int r = l + len - 1;
                dp[l][r] = dp[l][r - 1] + 1;
                for (int k = l; k < r; k++) {
                    if (s.charAt(k) == s.charAt(r)) {
                        dp[l][r] = Math.min(dp[l][r], dp[l][k] + dp[k + 1][r - 1]);
                    }
                }
            }
        }
        return dp[0][n - 1];
    }
}
